def kth_ordered(words, k):
    if not words or k < 1 or k > len(words):
        return None

    # Group words by their length
    groups = {}
    for word in words:
        length = len(word)
        if length not in groups:
            groups[length] = []
        groups[length].append(word)

    # Sort each group reverse-alphabetically and combine them
    sorted_words = []
    for length in sorted(groups.keys()):
        sorted_groups = sorted(groups[length], reverse=True)
        sorted_words.extend(sorted_groups)

    return sorted_words[k-1]
